export class ConsoleStreamer{isEnabled=!1;isWatch=!1;lines=0;constructor(s){this.isEnabled=s.isShowProgress,this.isWatch=s.isWatch}clearLines(s){if(s>0)for(let e=0;e<s;e++)process.stdout.moveCursor(0,-1),process.stdout.clearLine(1);process.stdout.cursorTo(0)}clearScreen(){process.stdout.write("[2J[1;1f")}update(s){this.clear(),process.stdout.write(`${s.join("\n")}\n`),this.lines=s.length}cast(s,e){this.isEnabled&&(Array.isArray(s)?this.update(s):this.update([`${s}${e&&"."!==e?` (${e})`:""}…`]))}clear(){this.isEnabled&&(this.isWatch?this.clearScreen():this.clearLines(this.lines))}}